// -------- GEOMETRY TYPES --------
export type Vector = [number, number];
export type LPoint = { pt: Vector; label: string };
export type LSegment = { p1: Vector; p2: Vector; label: string };
export type LAngle = {
  center: Vector;
  start: Vector;
  end: Vector;
  label: string;
};

export enum Obj {
  Point = "point",
  Segment = "segment",
  Text = "text",
  // Circle,
  Angle = "angle",
  ParallelTick = "parallel",
  EqualLengthTick = "equallength",
  Triangle = "triangle",
  EqualAngleTick = "equalangle",
  Tick = "tick",
  HiddenTick = "hiddentick",
  RightTick = "righttick",
  Quadrilateral = "rectangle",
}

export interface ParseObj {
  type: Obj.Point | Obj.Segment | Obj.Angle | Obj.Triangle | Obj.Quadrilateral;
  v: string;
}

// basic vector helpers used in UI and geometry code
export const vops = {
  add: (v1: Vector, v2: Vector): Vector => [v1[0] + v2[0], v1[1] + v2[1]],
  sub: (v1: Vector, v2: Vector): Vector => [v1[0] - v2[0], v1[1] - v2[1]],
  smul: (v: Vector, s: number): Vector => [v[0] * s, v[1] * s],
  div: (v: Vector, s: number): Vector => [v[0] / s, v[1] / s],
  mag: (v: Vector): number => Math.sqrt(v[0] * v[0] + v[1] * v[1]),
  dot: (v1: Vector, v2: Vector): number => v1[0] * v2[0] + v1[1] * v2[1],
  rot: (v: Vector, deg: number): Vector => {
    const rad = (deg * Math.PI) / 180;
    const [x, y] = v;
    const c = Math.cos(rad);
    const s = Math.sin(rad);
    return [c * x - s * y, s * x + c * y];
  },
};
